/**
 * Build-time index of every image that exists under hotel_images/ on Cloudinary.
 * Generated by scripts/build-hotel-media-manifest.mjs.
 *
 * A folder in `folders` was exhaustively enumerated: an image inside it that is
 * absent from `images` does not exist. A folder that is NOT listed is unknown —
 * callers fall back to probing it over the network, so hotels or images added
 * since the last manifest build still appear.
 */

const MANIFEST_URL = '/data/hotel-media.json';

/** @type {Promise<{images: Set<string>, folders: Set<string>}>|null} */
let manifestPromise = null;
/** @type {{images: Set<string>, folders: Set<string>}|null} */
let manifest = null;

const EMPTY = { images: new Set(), folders: new Set() };

/** Accepts `/assets/hotel_images/…` or `hotel_images/…`; returns the leading-slash form. */
function normalizeLogicalPath(path) {
    let value = String(path || '').trim();
    if (!value) return '';
    const query = value.indexOf('?');
    if (query >= 0) value = value.slice(0, query);
    if (value.startsWith('hotel_images/')) value = `/assets/${value}`;
    else if (value.startsWith('assets/hotel_images/')) value = `/${value}`;
    return value;
}

function folderOf(path) {
    const index = path.lastIndexOf('/');
    return index < 0 ? '' : path.slice(0, index);
}

/** Idempotent; the fetch happens once per page load. */
export function loadHotelMediaManifest() {
    if (manifestPromise) return manifestPromise;
    manifestPromise = fetch(MANIFEST_URL)
        .then((res) => {
            if (!res.ok) throw new Error(`HTTP ${res.status}`);
            return res.json();
        })
        .then((data) => {
            manifest = {
                images: new Set((data?.images || []).map(normalizeLogicalPath).filter(Boolean)),
                folders: new Set((data?.folders || []).map(normalizeLogicalPath).filter(Boolean))
            };
            return manifest;
        })
        .catch((error) => {
            // Degrade to the old network-probe path rather than rendering an empty site.
            console.warn('Hotel media manifest unavailable; probing Cloudinary instead.', error);
            manifest = EMPTY;
            return manifest;
        });
    return manifestPromise;
}

/**
 * @param {string} logicalPath
 * @returns {boolean|null} true/false when known, null when the folder was never enumerated.
 */
export function manifestImageExists(logicalPath) {
    if (!manifest) return null;
    const path = normalizeLogicalPath(logicalPath);
    if (!path) return null;
    if (manifest.images.has(path)) return true;
    return manifest.folders.has(folderOf(path)) ? false : null;
}
